import { IMessageComposer } from '@nitrots/nitro-renderer';

/**
 * Sends a simple request to the server asking for the
 * profile achievements list for the current user.
 */
export class ProfileAchievementsRequestComposer
    implements IMessageComposer<any[]>
{
    private _data: any[];

    constructor() {
        // no payload needed – server infers user from session
        this._data = [];
        console.log('[📤] ProfileAchievementsRequestComposer sent');
    }

    public getMessageArray(): any[] {
        return this._data;
    }

    public dispose(): void {
        return;
    }
}
